#include <stdio.h>
#include <stdlib.h>

int findTargetSumWays(int* nums, int numsSize, int target) {
    int totalSum = 0;
    for (int i = 0; i < numsSize; i++) {
        totalSum += nums[i];
    }
    if ((totalSum - target) < 0 || (totalSum - target) % 2 != 0) {
        return 0;
    }
    int subsetSum = (totalSum - target) / 2;
    int** dp = (int**)malloc(numsSize * sizeof(int*));
    for (int i = 0; i < numsSize; i++) {
        dp[i] = (int*)malloc((subsetSum + 1) * sizeof(int));
    }
    for (int i = 0; i < numsSize; i++) {
        for (int j = 0; j <= subsetSum; j++) {
            dp[i][j] = -1;
        }
    }
    return countSubsets(nums, numsSize - 1, subsetSum, dp);
}

int countSubsets(int* nums, int ind, int target, int** dp) {
    if (ind == 0) {
        if (target == 0 && nums[0] == 0) return 2;
        if (target == 0 || target == nums[0]) return 1;
        return 0;
    }
    if (dp[ind][target] != -1) return dp[ind][target];
    int notPick = countSubsets(nums, ind - 1, target, dp);
    int pick = 0;
    if (nums[ind] <= target) {
        pick = countSubsets(nums, ind - 1, target - nums[ind], dp);
    }
    return dp[ind][target] = pick + notPick;
}

