    findTargetSumWays(nums, target) {
        // Step 1: Calculate total sum of array
        let totalSum = nums.reduce((a, b) => a + b, 0);

        // Step 2: Feasibility check
        if ((totalSum - target) < 0 || (totalSum - target) % 2 !== 0)
            return 0;

        // Step 3: Problem reduces to subset sum
        let subsetSum = (totalSum - target) / 2;

        // Step 4: Memoization map to cache results
        let dp = new Map();

        // Step 5: Recursive helper function
        function countSubsets(ind, target) {
            // Base case: when at index 0
            if (ind === 0) {
                // Case 1: Both zero → two choices
                if (target === 0 && nums[0] === 0) return 2;
                // Case 2: Target matches 0 (exclude) or nums[0] (include)
                if (target === 0 || target === nums[0]) return 1;
                // Case 3: No valid subset
                return 0;
            }

            // Use key for memoization
            let key = ind + "," + target;
            if (dp.has(key)) return dp.get(key);

            // Option 1: Exclude current element
            let notPick = countSubsets(ind - 1, target);

            // Option 2: Include current element (only if <= target)
            let pick = 0;
            if (nums[ind] <= target) {
                pick = countSubsets(ind - 1, target - nums[ind]);
            }

            // Save in memo and return
            dp.set(key, pick + notPick);
            return dp.get(key);
        }

        // Start recursion from last index
        return countSubsets(nums.length - 1, subsetSum);
    }
}
